/**
 * Pangkas — Data Layer (db.js)
 * 
 * localStorage wrapper with prefixed keys, auto-backup,
 * export/import, and default seed data for an Indonesian barbershop.
 * 
 * Usage:
 *   DB.get('services')        → parsed value or null
 *   DB.set('services', [...]) → stores with 'pk_' prefix
 *   DB.def('services', [...]) → set only if key doesn't exist yet
 */

(function () {
  'use strict';

  const PREFIX = 'pk_';
  let _writeCount = 0;
  const BACKUP_EVERY = 10;

  // ─── Core CRUD ──────────────────────────────────────────────

  /**
   * Get a value from localStorage (auto JSON-parsed).
   * @param {string} key — logical key (prefix added automatically)
   * @returns {*} parsed value, or null if missing / corrupt
   */
  function get(key) {
    try {
      const raw = localStorage.getItem(PREFIX + key);
      return raw === null ? null : JSON.parse(raw);
    } catch (e) {
      console.warn('[DB] Gagal parse key:', key, e);
      return null;
    }
  }

  /**
   * Set a value in localStorage (auto JSON-stringified).
   * Triggers auto-backup every BACKUP_EVERY writes.
   * @param {string} key
   * @param {*} value
   */
  function set(key, value) {
    try {
      localStorage.setItem(PREFIX + key, JSON.stringify(value));
      _writeCount++;
      if (_writeCount >= BACKUP_EVERY) {
        _autoBackup();
        _writeCount = 0;
      }
    } catch (e) {
      console.error('[DB] Gagal simpan key:', key, e);
      // Kemungkinan quota exceeded
      if (e.name === 'QuotaExceededError') {
        alert('Penyimpanan penuh! Hapus data lama atau ekspor backup.');
      }
    }
  }

  /**
   * Set default — only writes if the key does NOT already exist.
   * @param {string} key
   * @param {*} defaultValue
   */
  function def(key, defaultValue) {
    if (get(key) === null) {
      set(key, defaultValue);
    }
  }

  /**
   * Remove a key from storage.
   * @param {string} key
   */
  function remove(key) {
    localStorage.removeItem(PREFIX + key);
  }

  /**
   * Check if a key exists.
   * @param {string} key
   * @returns {boolean}
   */
  function has(key) {
    return localStorage.getItem(PREFIX + key) !== null;
  }

  // ─── Auto-backup ────────────────────────────────────────────

  /**
   * Snapshot semua data pk_* ke pk_backup_latest.
   * Dipanggil otomatis setiap BACKUP_EVERY writes.
   */
  function _autoBackup() {
    try {
      const snapshot = _collectAll();
      snapshot._backupTime = new Date().toISOString();
      snapshot._version = 1;
      localStorage.setItem(PREFIX + 'backup_latest', JSON.stringify(snapshot));
      console.log('[DB] Auto-backup selesai —', Object.keys(snapshot).length, 'keys');
    } catch (e) {
      console.warn('[DB] Auto-backup gagal:', e);
    }
  }

  /**
   * Kumpulkan semua data pk_* (kecuali backup itu sendiri).
   * @returns {Object}
   */
  function _collectAll() {
    const data = {};
    for (let i = 0; i < localStorage.length; i++) {
      const fullKey = localStorage.key(i);
      if (fullKey.startsWith(PREFIX) && fullKey !== PREFIX + 'backup_latest') {
        const logicalKey = fullKey.slice(PREFIX.length);
        try {
          data[logicalKey] = JSON.parse(localStorage.getItem(fullKey));
        } catch (_) {
          data[logicalKey] = localStorage.getItem(fullKey);
        }
      }
    }
    return data;
  }

  // ─── Export / Import ────────────────────────────────────────

  /**
   * Ekspor semua data sebagai JSON string (untuk download/share).
   * @returns {string} JSON
   */
  function exportData() {
    const snapshot = _collectAll();
    snapshot._exportTime = new Date().toISOString();
    snapshot._version = 1;
    return JSON.stringify(snapshot, null, 2);
  }

  /**
   * Download ekspor sebagai file .json.
   */
  function downloadExport() {
    const json = exportData();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'pangkas-backup-' + new Date().toISOString().slice(0, 10) + '.json';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }

  /**
   * Impor data dari JSON string. Merge — keys yang ada akan ditimpa.
   * @param {string} jsonString
   * @returns {boolean} true jika berhasil
   */
  function importData(jsonString) {
    try {
      const data = JSON.parse(jsonString);
      // Abaikan metadata keys
      const skipKeys = ['_exportTime', '_backupTime', '_version'];
      let count = 0;
      for (const [key, value] of Object.entries(data)) {
        if (!skipKeys.includes(key)) {
          localStorage.setItem(PREFIX + key, JSON.stringify(value));
          count++;
        }
      }
      console.log('[DB] Import berhasil —', count, 'keys');
      return true;
    } catch (e) {
      console.error('[DB] Import gagal:', e);
      return false;
    }
  }

  /**
   * Restore dari backup terakhir.
   * @returns {boolean}
   */
  function restoreBackup() {
    const raw = localStorage.getItem(PREFIX + 'backup_latest');
    if (!raw) {
      console.warn('[DB] Tidak ada backup untuk di-restore');
      return false;
    }
    return importData(raw);
  }

  /**
   * Hapus SEMUA data pk_* (termasuk backup). Hati-hati!
   */
  function clearAll() {
    const keysToRemove = [];
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k.startsWith(PREFIX)) keysToRemove.push(k);
    }
    keysToRemove.forEach(k => localStorage.removeItem(k));
    console.log('[DB] Semua data dihapus —', keysToRemove.length, 'keys');
  }

  // ─── Seed Data ──────────────────────────────────────────────

  const DEFAULT_SERVICES = [
    { id: 'svc-001', name: 'Potong Rambut', price: 35000, category: 'potong', active: true, duration: 30 },
    { id: 'svc-002', name: 'Cukur Jenggot', price: 20000, category: 'cukur', active: true, duration: 15 },
    { id: 'svc-003', name: 'Cuci Rambut', price: 15000, category: 'cuci', active: true, duration: 10 },
    { id: 'svc-004', name: 'Potong + Cuci', price: 45000, category: 'potong', active: true, duration: 40 },
    { id: 'svc-005', name: 'Warna Rambut', price: 100000, category: 'warna', active: true, duration: 60 },
    { id: 'svc-006', name: 'Hair Tonic', price: 25000, category: 'treatment', active: true, duration: 15 },
    { id: 'svc-007', name: 'Creambath', price: 50000, category: 'treatment', active: true, duration: 30 },
  ];

  const DEFAULT_CATEGORIES = [
    { id: 'cat-potong', name: 'Potong', icon: '✂️' },
    { id: 'cat-cukur', name: 'Cukur', icon: '🪒' },
    { id: 'cat-cuci', name: 'Cuci', icon: '🧴' },
    { id: 'cat-warna', name: 'Warna', icon: '🎨' },
    { id: 'cat-treatment', name: 'Treatment', icon: '💆' },
  ];

  const DEFAULT_SETTINGS = {
    shop: {
      name: '',
      address: '',
      phone: '',
      logo: null,
      tagline: '',
    },
    commission: 40,           // persen komisi tukang cukur
    memberVisits: 10,         // kunjungan untuk jadi member
    memberReward: '1x Potong Gratis',
    sessionTimeout: 15,       // menit idle → auto logout
    queueEstimate: 20,        // estimasi menit per antrian
  };

  const DEFAULT_PRODUCTS = [
    { id: 'prod-001', name: 'Pomade Gatsby', price: 45000, stock: 10, category: 'styling', active: true },
    { id: 'prod-002', name: 'Shampo Makarizo', price: 25000, stock: 15, category: 'shampo', active: true },
    { id: 'prod-003', name: 'Hair Tonic NR', price: 30000, stock: 8, category: 'treatment', active: true },
    { id: 'prod-004', name: 'Wax Rambut', price: 50000, stock: 5, category: 'styling', active: true },
  ];

  /**
   * Seed default data — hanya tulis jika belum ada (def).
   * Dipanggil saat pertama kali buka app.
   */
  function seed() {
    def('services', DEFAULT_SERVICES);
    def('categories', DEFAULT_CATEGORIES);
    def('settings', DEFAULT_SETTINGS);
    def('products', DEFAULT_PRODUCTS);
    def('barbers', []);         // daftar tukang cukur
    def('members', []);         // daftar member
    def('transactions', []);    // riwayat transaksi
    def('queue', []);           // antrian aktif
    def('expenses', []);        // pengeluaran operasional
    def('firstRun', true);      // flag pertama kali
    console.log('[DB] Seed data siap');
  }

  // ─── Public API ─────────────────────────────────────────────

  window.DB = {
    get,
    set,
    def,
    remove,
    has,
    seed,
    exportData,
    downloadExport,
    importData,
    restoreBackup,
    clearAll,
    // Expose defaults for reference
    DEFAULTS: {
      services: DEFAULT_SERVICES,
      categories: DEFAULT_CATEGORIES,
      settings: DEFAULT_SETTINGS,
      products: DEFAULT_PRODUCTS,
    },
  };

  console.log('[DB] Module loaded ✓');
})();

/**
 * Pangkas — Utility Functions (utils.js)
 * 
 * Format angka, tanggal, waktu dalam format Indonesia.
 * Helper untuk WhatsApp, debounce, deep clone, dan lainnya.
 */

(function () {
  'use strict';

  // ─── Nama-nama Indonesia ────────────────────────────────────

  const HARI = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'];

  const BULAN = [
    'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni',
    'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'
  ];

  const BULAN_PENDEK = [
    'Jan', 'Feb', 'Mar', 'Apr', 'Mei', 'Jun',
    'Jul', 'Ags', 'Sep', 'Okt', 'Nov', 'Des'
  ];

  // ─── Format Uang ────────────────────────────────────────────

  /**
   * Format angka ke Rupiah. 35000 → "Rp 35.000"
   * @param {number} num
   * @returns {string}
   */
  function rp(num) {
    if (num === null || num === undefined || isNaN(num)) return 'Rp 0';
    const abs = Math.abs(Math.round(num));
    const formatted = abs.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.');
    return (num < 0 ? '-' : '') + 'Rp ' + formatted;
  }

  // ─── Format Tanggal ─────────────────────────────────────────

  /**
   * Format tanggal ke format Indonesia.
   * "6 April 2026" atau "Sen, 6 Apr 2026" (short)
   * @param {Date|string|number} date
   * @param {boolean} [short=false]
   * @returns {string}
   */
  function formatDate(date, short) {
    const d = _toDate(date);
    if (!d) return '-';

    if (short) {
      return HARI[d.getDay()].slice(0, 3) + ', ' +
        d.getDate() + ' ' +
        BULAN_PENDEK[d.getMonth()] + ' ' +
        d.getFullYear();
    }

    return d.getDate() + ' ' + BULAN[d.getMonth()] + ' ' + d.getFullYear();
  }

  /**
   * Format waktu ke HH:MM.
   * @param {Date|string|number} date
   * @returns {string}
   */
  function formatTime(date) {
    const d = _toDate(date);
    if (!d) return '--:--';
    return _pad(d.getHours()) + ':' + _pad(d.getMinutes());
  }

  /**
   * Format lengkap: "Sen, 6 Apr 2026 · 14:30"
   * @param {Date|string|number} date
   * @returns {string}
   */
  function formatDateTime(date) {
    return formatDate(date, true) + ' · ' + formatTime(date);
  }

  // ─── ID Generator ───────────────────────────────────────────

  /**
   * Generate unique ID: "prefix-timestamp-random"
   * @param {string} [prefix='id']
   * @returns {string}
   */
  function generateId(prefix) {
    prefix = prefix || 'id';
    const ts = Date.now().toString(36);
    const rnd = Math.random().toString(36).slice(2, 7);
    return prefix + '-' + ts + '-' + rnd;
  }

  // ─── WhatsApp ───────────────────────────────────────────────

  /**
   * Buat WhatsApp URL. Otomatis konversi 08xx → 628xx.
   * @param {string} phone — nomor telepon (08xx, +62xx, 62xx)
   * @param {string} [message='']
   * @returns {string} wa.me URL
   */
  function waLink(phone, message) {
    if (!phone) return '#';
    // Bersihkan: hapus spasi, strip, kurung
    let clean = phone.replace(/[\s\-\(\)\+]/g, '');
    // 08xx → 628xx
    if (clean.startsWith('08')) {
      clean = '62' + clean.slice(1);
    }
    // Pastikan dimulai 62
    if (!clean.startsWith('62')) {
      clean = '62' + clean;
    }
    let url = 'https://wa.me/' + clean;
    if (message) {
      url += '?text=' + encodeURIComponent(message);
    }
    return url;
  }

  // ─── Debounce & Clone ───────────────────────────────────────

  /**
   * Debounce — tunda eksekusi fungsi sampai idle.
   * @param {Function} fn
   * @param {number} [delay=300] ms
   * @returns {Function}
   */
  function debounce(fn, delay) {
    delay = delay || 300;
    let timer = null;
    return function () {
      const ctx = this;
      const args = arguments;
      clearTimeout(timer);
      timer = setTimeout(function () {
        fn.apply(ctx, args);
      }, delay);
    };
  }

  /**
   * Deep clone object (structured clone fallback ke JSON).
   * @param {*} obj
   * @returns {*}
   */
  function deepClone(obj) {
    if (obj === null || typeof obj !== 'object') return obj;
    try {
      return structuredClone(obj);
    } catch (_) {
      return JSON.parse(JSON.stringify(obj));
    }
  }

  // ─── Time Ago ───────────────────────────────────────────────

  /**
   * Hitung waktu relatif dalam bahasa Indonesia.
   * "baru saja", "5 menit lalu", "2 jam lalu", "3 hari lalu", etc.
   * @param {Date|string|number} date
   * @returns {string}
   */
  function getTimeAgo(date) {
    const d = _toDate(date);
    if (!d) return '-';

    const now = Date.now();
    const diff = now - d.getTime(); // ms

    if (diff < 0) return 'baru saja';

    const detik = Math.floor(diff / 1000);
    const menit = Math.floor(detik / 60);
    const jam = Math.floor(menit / 60);
    const hari = Math.floor(jam / 24);
    const minggu = Math.floor(hari / 7);
    const bulan = Math.floor(hari / 30);

    if (detik < 60) return 'baru saja';
    if (menit < 60) return menit + ' menit lalu';
    if (jam < 24) return jam + ' jam lalu';
    if (hari < 7) return hari + ' hari lalu';
    if (minggu < 4) return minggu + ' minggu lalu';
    if (bulan < 12) return bulan + ' bulan lalu';
    return Math.floor(hari / 365) + ' tahun lalu';
  }

  // ─── Day Names ──────────────────────────────────────────────

  /**
   * Nama hari Indonesia.
   * @param {Date|string|number} date
   * @returns {string} "Senin", "Selasa", etc.
   */
  function getDayName(date) {
    const d = _toDate(date);
    if (!d) return '-';
    return HARI[d.getDay()];
  }

  // ─── Date Checks ────────────────────────────────────────────

  /**
   * Apakah tanggal = hari ini?
   * @param {Date|string|number} date
   * @returns {boolean}
   */
  function isToday(date) {
    const d = _toDate(date);
    if (!d) return false;
    const now = new Date();
    return d.getFullYear() === now.getFullYear() &&
      d.getMonth() === now.getMonth() &&
      d.getDate() === now.getDate();
  }

  /**
   * Apakah tanggal masuk minggu ini? (Senin–Minggu)
   * @param {Date|string|number} date
   * @returns {boolean}
   */
  function isThisWeek(date) {
    const d = _toDate(date);
    if (!d) return false;
    const now = new Date();
    // Awal minggu = Senin
    const startOfWeek = new Date(now);
    const day = startOfWeek.getDay();
    const diff = day === 0 ? 6 : day - 1; // Senin = 0
    startOfWeek.setDate(startOfWeek.getDate() - diff);
    startOfWeek.setHours(0, 0, 0, 0);

    const endOfWeek = new Date(startOfWeek);
    endOfWeek.setDate(endOfWeek.getDate() + 7);

    return d >= startOfWeek && d < endOfWeek;
  }

  /**
   * Apakah tanggal masuk bulan ini?
   * @param {Date|string|number} date
   * @returns {boolean}
   */
  function isThisMonth(date) {
    const d = _toDate(date);
    if (!d) return false;
    const now = new Date();
    return d.getFullYear() === now.getFullYear() &&
      d.getMonth() === now.getMonth();
  }

  // ─── Internal Helpers ───────────────────────────────────────

  /**
   * Konversi input ke Date object.
   * @param {Date|string|number} v
   * @returns {Date|null}
   */
  function _toDate(v) {
    if (!v) return null;
    if (v instanceof Date) return isNaN(v.getTime()) ? null : v;
    const d = new Date(v);
    return isNaN(d.getTime()) ? null : d;
  }

  /**
   * Pad angka jadi 2 digit: 5 → "05"
   * @param {number} n
   * @returns {string}
   */
  function _pad(n) {
    return n < 10 ? '0' + n : '' + n;
  }

  // ─── Public API ─────────────────────────────────────────────

  window.Utils = {
    rp,
    formatDate,
    formatTime,
    formatDateTime,
    generateId,
    waLink,
    debounce,
    deepClone,
    getTimeAgo,
    getDayName,
    isToday,
    isThisWeek,
    isThisMonth,
    // Expose constants
    HARI,
    BULAN,
    BULAN_PENDEK,
  };

  console.log('[Utils] Module loaded ✓');
})();

/**
 * Pangkas — App Core & Router (app.js)
 * 
 * State management, hash-based routing, session timeout,
 * event bus, and app initialization.
 * 
 * Depends on: db.js, utils.js, ui.js
 */

(function () {
  'use strict';

  // ─── State ──────────────────────────────────────────────────

  const state = {
    currentUser: null,       // { id, name, role, pin }
    currentPage: 'home',     // active route
    previousPage: null,      // for back navigation
    cart: [],                // [ { item, qty, type:'service'|'product' } ]
    queue: [],               // synced from DB
    isLoading: false,
    lastActivity: Date.now(),
    sessionTimer: null,
  };

  // ─── Event Bus ──────────────────────────────────────────────
  // Simple pub/sub for cross-component communication.

  const _listeners = {};

  /**
   * Subscribe to an event.
   * @param {string} event
   * @param {Function} callback
   * @returns {Function} unsubscribe function
   */
  function on(event, callback) {
    if (!_listeners[event]) _listeners[event] = [];
    _listeners[event].push(callback);
    return function () {
      off(event, callback);
    };
  }

  /**
   * Unsubscribe from an event.
   * @param {string} event
   * @param {Function} callback
   */
  function off(event, callback) {
    if (!_listeners[event]) return;
    _listeners[event] = _listeners[event].filter(function (fn) {
      return fn !== callback;
    });
  }

  /**
   * Emit an event ke semua subscribers.
   * @param {string} event
   * @param {*} [data]
   */
  function emit(event, data) {
    if (!_listeners[event]) return;
    _listeners[event].forEach(function (fn) {
      try {
        fn(data);
      } catch (e) {
        console.error('[App] Event handler error:', event, e);
      }
    });
  }

  // ─── Router ─────────────────────────────────────────────────
  // Hash-based: #kasir, #antrian, #member, #laporan, #pengaturan, etc.

  const routes = {};

  /**
   * Register a page route.
   * @param {string} name — route name (tanpa #)
   * @param {Object} handler — { init(), teardown(), title }
   */
  function registerRoute(name, handler) {
    routes[name] = handler;
  }

  /**
   * Navigate ke halaman.
   * @param {string} page — route name (tanpa #)
   * @param {Object} [params] — optional params
   */
  function navigate(page, params) {
    // Teardown halaman sebelumnya
    if (state.currentPage && routes[state.currentPage] && routes[state.currentPage].teardown) {
      try {
        routes[state.currentPage].teardown();
      } catch (e) {
        console.warn('[Router] Teardown error:', state.currentPage, e);
      }
    }

    state.previousPage = state.currentPage;
    state.currentPage = page;

    // Update hash (tanpa trigger hashchange lagi)
    const newHash = '#' + page;
    if (window.location.hash !== newHash) {
      history.pushState(null, '', newHash);
    }

    // Init halaman baru
    if (routes[page]) {
      try {
        if (routes[page].title) {
          document.title = routes[page].title + ' — Pangkas';
        }
        routes[page].init(params);
      } catch (e) {
        console.error('[Router] Init error:', page, e);
      }
    } else {
      console.warn('[Router] Route tidak ditemukan:', page);
      _renderNotFound(page);
    }

    // Update bottom nav
    if (window.UI && UI.renderBottomNav) {
      UI.renderBottomNav(page);
    }

    emit('navigate', { page: page, params: params, previous: state.previousPage });
    _touchActivity();
  }

  /**
   * Go back ke halaman sebelumnya.
   */
  function goBack() {
    if (state.previousPage) {
      navigate(state.previousPage);
    } else {
      navigate('home');
    }
  }

  /**
   * Handle hashchange event.
   */
  function _onHashChange() {
    const hash = window.location.hash.slice(1) || 'home';
    // Jangan navigate kalau sudah di halaman yang sama
    if (hash !== state.currentPage) {
      navigate(hash);
    }
  }

  /**
   * Render 404 page.
   */
  function _renderNotFound(page) {
    var content = document.getElementById('app-content');
    if (content) {
      content.innerHTML =
        '<div style="text-align:center;padding:60px 20px;">' +
        '<div style="font-size:64px;margin-bottom:16px;">🤷</div>' +
        '<h2 style="color:#fff;margin-bottom:8px;">Halaman Tidak Ditemukan</h2>' +
        '<p style="color:#888;">Route "' + page + '" tidak ada.</p>' +
        '<button onclick="App.navigate(\'home\')" style="margin-top:20px;padding:12px 24px;' +
        'background:#0ABFBC;color:#000;border:none;border-radius:8px;font-weight:600;cursor:pointer;">' +
        'Kembali ke Home</button></div>';
    }
  }

  // ─── Session Timeout ────────────────────────────────────────

  /**
   * Reset activity timestamp.
   */
  function _touchActivity() {
    state.lastActivity = Date.now();
  }

  /**
   * Mulai session timer — cek idle setiap menit.
   */
  function _startSessionTimer() {
    // Bersihkan timer lama
    if (state.sessionTimer) clearInterval(state.sessionTimer);

    state.sessionTimer = setInterval(function () {
      if (!state.currentUser) return; // belum login

      var settings = DB.get('settings') || {};
      var timeoutMs = (settings.sessionTimeout || 15) * 60 * 1000;
      var idle = Date.now() - state.lastActivity;

      if (idle >= timeoutMs) {
        console.log('[App] Session timeout — auto logout');
        logout();
        if (window.UI) {
          UI.showToast('Sesi berakhir — silakan login kembali', 'info');
        }
      }
    }, 60 * 1000); // cek setiap menit
  }

  /**
   * Track user activity (touch, click, key).
   */
  function _setupActivityTracking() {
    var events = ['touchstart', 'click', 'keydown', 'scroll'];
    events.forEach(function (evt) {
      document.addEventListener(evt, _touchActivity, { passive: true });
    });
  }

  // ─── Auth ───────────────────────────────────────────────────

  /**
   * Login user.
   * @param {Object} user — { id, name, role, pin }
   */
  function login(user) {
    state.currentUser = user;
    state.lastActivity = Date.now();
    DB.set('currentSession', {
      userId: user.id,
      loginTime: new Date().toISOString(),
    });
    emit('login', user);
    console.log('[App] Login:', user.name, '(' + user.role + ')');
  }

  /**
   * Logout user.
   */
  function logout() {
    var user = state.currentUser;
    state.currentUser = null;
    state.cart = [];
    DB.remove('currentSession');
    emit('logout', user);
    navigate('login');
    console.log('[App] Logout');
  }

  /**
   * Cek apakah user sudah login.
   * @returns {boolean}
   */
  function isLoggedIn() {
    return state.currentUser !== null;
  }

  // ─── Cart ───────────────────────────────────────────────────

  /**
   * Tambah item ke cart.
   * @param {Object} item — service atau product
   * @param {string} type — 'service' | 'product'
   */
  function addToCart(item, type) {
    type = type || 'service';
    // Cek apakah sudah ada di cart
    var existing = state.cart.find(function (c) {
      return c.item.id === item.id && c.type === type;
    });
    if (existing) {
      existing.qty++;
    } else {
      state.cart.push({ item: item, qty: 1, type: type });
    }
    emit('cartUpdate', state.cart);
  }

  /**
   * Hapus item dari cart.
   * @param {string} itemId
   */
  function removeFromCart(itemId) {
    state.cart = state.cart.filter(function (c) {
      return c.item.id !== itemId;
    });
    emit('cartUpdate', state.cart);
  }

  /**
   * Kosongkan cart.
   */
  function clearCart() {
    state.cart = [];
    emit('cartUpdate', state.cart);
  }

  /**
   * Total harga cart.
   * @returns {number}
   */
  function getCartTotal() {
    return state.cart.reduce(function (sum, c) {
      return sum + (c.item.price * c.qty);
    }, 0);
  }

  // ─── Initialization ─────────────────────────────────────────

  /**
   * Inisialisasi app.
   * Seed data → cek first run → route ke onboarding atau login.
   */
  function init() {
    console.log('[App] Initializing Pangkas...');

    // 1. Seed default data
    DB.seed();

    // 2. Setup activity tracking & session timer
    _setupActivityTracking();
    _startSessionTimer();

    // 3. Listen hash changes
    window.addEventListener('hashchange', _onHashChange);

    // 4. Handle browser back/forward
    window.addEventListener('popstate', function () {
      var hash = window.location.hash.slice(1) || 'home';
      if (hash !== state.currentPage) {
        navigate(hash);
      }
    });

    // 5. Cek first run
    var isFirstRun = DB.get('firstRun');
    var settings = DB.get('settings') || {};

    if (isFirstRun && !settings.shop.name) {
      // Pertama kali — tampilkan onboarding
      console.log('[App] First run — onboarding');
      navigate('onboarding');
    } else {
      // Sudah pernah setup — cek session
      var session = DB.get('currentSession');
      if (session) {
        // Restore session — cari user
        var barbers = DB.get('barbers') || [];
        var user = barbers.find(function (b) { return b.id === session.userId; });
        if (user) {
          state.currentUser = user;
          emit('login', user);
        }
      }

      // Route ke hash saat ini, atau home
      var hash = window.location.hash.slice(1);
      if (hash && routes[hash]) {
        navigate(hash);
      } else {
        navigate(state.currentUser ? 'home' : 'login');
      }
    }

    // 6. Sync queue dari DB
    state.queue = DB.get('queue') || [];

    // 7. Register service worker
    _registerSW();

    emit('appReady');
    console.log('[App] Ready ✓');
  }

  /**
   * Register service worker untuk PWA.
   */
  function _registerSW() {
    if ('serviceWorker' in navigator) {
      navigator.serviceWorker.register('/sw.js').then(function (reg) {
        console.log('[App] Service worker registered:', reg.scope);
      }).catch(function (e) {
        console.warn('[App] Service worker gagal:', e);
      });
    }
  }

  // ─── Public API ─────────────────────────────────────────────

  window.App = {
    // State (read-only access)
    get state() { return state; },

    // Router
    navigate,
    goBack,
    registerRoute,

    // Auth
    login,
    logout,
    isLoggedIn,

    // Cart
    addToCart,
    removeFromCart,
    clearCart,
    getCartTotal,

    // Event bus
    on,
    off,
    emit,

    // Lifecycle
    init,
  };

  console.log('[App] Module loaded ✓');
})();

/**
 * Pangkas — UI Helpers (ui.js)
 * 
 * Modal, toast, confirm dialog, loading overlay, animations,
 * dan bottom navigation. Semua dalam bahasa Indonesia.
